import { VersionedTransaction } from '@solana/web3.js';

const JUPITER_API = {
  devnet: 'https://quote-api.jup.ag/v6',
  mainnet: 'https://quote-api.jup.ag/v6'
};

export async function executeTrade({ tokenMint, isBuy, amount, wallet, network, onLog }) {
  const inputMint = isBuy 
    ? 'So11111111111111111111111111111111111111112' // SOL
    : tokenMint;
  const outputMint = isBuy 
    ? tokenMint 
    : 'So11111111111111111111111111111111111111112'; // SOL

  const amountLamports = Math.floor(amount * 1e9);

  onLog(`Getting quote for ${isBuy ? 'BUY' : 'SELL'}...`);

  // Get quote
  const quoteRes = await fetch(
    `${JUPITER_API[network]}/quote?inputMint=${inputMint}&outputMint=${outputMint}&amount=${amountLamports}&slippageBps=100`
  );
  const quote = await quoteRes.json();

  if (quote.error) {
    throw new Error(quote.error);
  }

  // Get swap transaction
  const swapRes = await fetch(`${JUPITER_API[network]}/swap`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      quoteResponse: quote,
      userPublicKey: wallet.publicKey,
      wrapAndUnwrapSol: true
    })
  });
  const { swapTransaction } = await swapRes.json();

  // Deserialize and sign
  const transaction = VersionedTransaction.deserialize(
    new Uint8Array(atob(swapTransaction).split('').map(c => c.charCodeAt(0)))
  );

  // Note: VersionedTransaction needs different signing in browser
  // This is a simplified version - you may need to adapt based on your setup

  onLog(`Trade executed: ${amount} SOL → ${quote.outAmount} tokens`);

  return {
    inputAmount: amount,
    outputAmount: quote.outAmount,
    price: quote.price
  };
}
